        ["valid_token_789"] = "guest"
    }
    
    local user_role = valid_tokens[token]
    if not user_role then
        ngx.status = 403
        ngx.say('Forbidden: Invalid or expired token')
        ngx.exit(403)
        return false
    end
    
    -- Check role permissions
    local required_role = "admin"
